public class ETG_CustKnockOffContract implements SysOperationValidatable
{
    FromDate                fromDate;
    ToDate                  toDate;
    CustAccount             custAccount;
    DimensionSetName        financialDimSet;
    boolean              financialDimensions;

}

Method.Source:
[DataMemberAttribute('CustAccount'),
SysOperationLabelAttribute(literalStr("@SYS7149")),
SysOperationHelpTextAttribute(literalStr("@SYS7149"))]
public CustAccount parmCustAccount(CustAccount _custAccount = custAccount)
{
    custAccount = _custAccount;
    return custAccount;
}

[DataMemberAttribute('FromDate'),
SysOperationLabelAttribute(literalStr("@SYS5209")),
SysOperationHelpTextAttribute(literalStr("@SYS5209"))]
//SysOperationDisplayOrderAttribute('1')]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[DataMemberAttribute('ToDate'),
SysOperationLabelAttribute(literalStr("@SYS14656")),
SysOperationHelpTextAttribute(literalStr("@SYS14656"))]
    //SysOperationDisplayOrderAttribute('2')]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

[
    DataMemberAttribute('FinancialDimensions'),
    SysOperationLabelAttribute(literalStr("Financial Dimensions")),
    SysOperationGroupMemberAttribute('Criteria')
    //SysOperationDisplayOrderAttribute('13')
]
public boolean parmFinancialDimensions(boolean _financialDimensions = financialDimensions)
{
    financialDimensions = _financialDimensions;
    return financialDimensions;
}

[
    DataMemberAttribute('DimensionSetName'),
    SysOperationLabelAttribute(literalStr("Financial dimension set")),
    SysOperationGroupMemberAttribute('Criteria')
    //SysOperationDisplayOrderAttribute('14')
]
public DimensionSetName parmFinancialDimSet(DimensionSetName _financialDimSet = financialDimSet)
{
    financialDimSet = _financialDimSet;
    return financialDimSet;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180311"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180217"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@SYS300457");
    }
    return isValid;
}
